var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"선배! 어디에 있어?","JPN":"先輩！　どこにいるの？","ENG":"Shiyoon! Where are you?","TWN":"前輩！你在哪裡？"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이쪽입니다.","JPN":"こっちですよ。","ENG":"Here.","TWN":"我在這裡。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이 안개와 바람은 대체 뭐야? 앞이 하나도 안 보여!","JPN":"この霧と風はいったい何なの？　前が全然見えないよ！","ENG":"What’s up with all the wind and fog? I can’t see a thing!","TWN":"這裡的霧跟風會不會太誇張？根本看不到前面啊！"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이 지역에 존재하는 차원 폭풍 때문인 것 같네요.","JPN":"この地域に発生している次元の暴風のようですね。","ENG":"I think it’s because of the dimensional storm.","TWN":"應該是因為這個地區的次元風暴。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"관리국 기상정보에 따르면 지금이 그나마 이쪽 루트의 차원 폭풍이 약해지는 시간대입니다.","JPN":"管理局の気象情報によると、\\nちょうど今がこのあたりの次元の暴風が弱まる時間帯です。","ENG":"According to the Administration’s forecast, now is the time when the storm on this route gets calmer.","TWN":"根據管理局的氣象報告，現在應該是這一條路線的次元風暴減弱的時段。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"시간이 조금만 지나면 차원 함선도 제대로 움직이기 어려울 겁니다.","JPN":"このタイミングを逃すと次元艦船も動かせなくなるでしょう。","ENG":"Soon it will get really serious; even the Dimensional Ship won’t be able to move.","TWN":"再過些時間，很可能連次元艦船都很難移動。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그 정도야?","JPN":"そんなに？","ENG":"It’s that bad?","TWN":"這麼誇張？"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"물건만 가지고 오면 되는 줄 알았는데……. 역시 쉬운 게 없네.","JPN":"物を取ってくるだけで終わると思ってたのに……やっぱり簡単にはいかないね。","ENG":"I thought this was just a simple retrieval mission... But I guess there are no easy jobs.","TWN":"我還以為只要帶傢伙來就好……果然沒有那麼簡單的事。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하. 남의 돈 받아내기가 쉬울 리 있나요.","JPN":"ハハ。お金を稼ぐのは大変ですから。","ENG":"Haha. That’s why people pay us the big bucks.","TWN":"哈哈，要賺別的人錢哪有這麼容易的。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"할 수 없지, 뭐.","JPN":"しょうがないね。","ENG":"Yeah, you’re right.","TWN":"也只能這樣囉～"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"상황이 더 나빠지기 전에 빨리 가서 일 끝내고 쉬자고…… ","JPN":"状況がもっと悪くなる前に早く片付けて……","ENG":"Let's finish this before it gets worse...","TWN":"在情況更惡劣之前，趕緊把事情辦完回家休息吧…… "},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":" 응?","JPN":"ん？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NULL_QM","text":{"KOREA":"여봐라, 혹시 거기 듣고 있는 필멸자 녀석 있느냐?","JPN":"だれかこの声を聞いている定命の者はおらぬか？","ENG":"Hail, are there any mortals who can hear me?","TWN":"喂，那裡有必滅者在聽嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NULL_QM","text":{"KOREA":"이게 그러니까…… 뭐라고 하더라, 시종?","JPN":"これは……僕よ、なんといったものだったか？","ENG":"This is... um, what do you call it, my servant?","TWN":"這是那個……那個什麼？"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"조난 신호입니다, 주인님.","JPN":"遭難信号でございます、ご主人様。","ENG":"It’s a distress call, Mistress.","TWN":"主人，是求救訊號。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NULL_QM","text":{"KOREA":"그래! 조난 신호다!","JPN":"そうじゃ！　遭難信号じゃ！","ENG":"Yes, this is a distress call!","TWN":"沒錯！就是求救訊號！"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NULL_QM","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};